SELECT count(*) FROM company_type, movie_companies, title, movie_info, info_type, company_name, movie_keyword, cast_info, kind_type WHERE movie_companies.company_type_id = company_type.id AND movie_companies.movie_id = title.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_companies.company_id = company_name.id AND movie_keyword.movie_id = title.id AND cast_info.movie_id = title.id AND title.kind_id = kind_type.id;